#!/usr/bin/env bun
// Generated by minsky compile. Do not edit directly.
// Source: .minsky/hooks/check-generated-file-edit.ts

// PreToolUse hook: block edits to generated files identified by banner markers.
//
// Rationale: Generated files (compiled outputs from rules_compile, codegen tools,
// etc.) carry a "Generated by" or "Do not edit" banner in their first few lines.
// When an agent edits such a file directly instead of editing the canonical source
// and re-running the compiler, it creates source/derivative tangles that corrupt
// the pipeline. This hook reads the first 5 lines of the target file and blocks
// the edit when a generation-banner marker is found.
//
// Originating incident: mt#1678 PR #1012 (2026-05-08) — the agent edited
// CLAUDE.md, AGENTS.md, and .cursor/rules/hook-files.mdc directly, when those
// are all compiled outputs from .minsky/rules/hook-files.mdc via rules_compile.
//
// Behaviour:
//   - Reads first 5 lines of target file.
//   - Matches against a set of common generation-banner regexes.
//   - On match: DENY with structured message naming the marker, file path, and
//     instruction to find and edit the canonical source.
//   - On no match / file missing / read error: permit (fail-open).
//   - Override: MINSKY_FORCE_EDIT_GENERATED=1 bypasses with an audit log entry.
//
// Supported tool shapes:
//   - mcp__minsky__session_search_replace / session_edit_file / session_write_file:
//     path field in tool_input; resolved against input.cwd for session tools.
//   - Edit (Claude Code): file_path field in tool_input (absolute).
//   - Write (Claude Code): file_path field in tool_input (absolute).
//
// @see mt#1699 — implementation task
// @see mt#1678 — originating incident (source/derivative tangle)
// @see .minsky/rules/hook-files.mdc — canonical rule documentation

import { join, isAbsolute } from "node:path";
import { readInput, writeOutput, readHostCap, deriveBudgets, DEFAULT_HOST_CAP_SEC } from "./types";
import type { ToolHookInput } from "./types";

// ---------------------------------------------------------------------------
// Budget derivation from host cap (mt#1546 pattern)
// ---------------------------------------------------------------------------
//
// The hook is essentially synchronous (reads a few lines from a file — no
// network calls, no subprocesses), so the budget is mostly defensive. We
// follow the check-branch-fresh.ts pattern of deriving budgets from the host
// cap at entrypoint time for structural consistency with other hooks.

const DEFAULT_BUDGETS = deriveBudgets(DEFAULT_HOST_CAP_SEC);
let OVERALL_BUDGET_MS = DEFAULT_BUDGETS.overallBudgetMs;

export function applyHostCap(hostCapSec: number): void {
  const budgets = deriveBudgets(hostCapSec);
  OVERALL_BUDGET_MS = budgets.overallBudgetMs;
}

/** Test-only: read the current module-level budget. */
export function getCurrentBudget(): number {
  return OVERALL_BUDGET_MS;
}

// ---------------------------------------------------------------------------
// Generation-banner regex patterns
// ---------------------------------------------------------------------------
//
// Each regex matches a common banner form used by code generators to signal
// that the file should not be edited directly. Checked against the first
// 5 lines of the target file only (banners are always at the top).
//
// Imported from the shared single-source-of-truth module so the rules-compile
// writers and this detection hook can't drift (mt#1798). To add a new banner
// form, edit `src/domain/rules/compile/banner-constants.ts`.

import { GENERATION_BANNER_PATTERNS } from "../../packages/domain/src/rules/compile/banner-constants";
export { GENERATION_BANNER_PATTERNS };

// ---------------------------------------------------------------------------
// Path extraction by tool name
// ---------------------------------------------------------------------------

/**
 * Extract the target file path from tool_input based on tool_name.
 *
 * Returns null if the path can't be extracted (shape mismatch). The caller
 * should permit (fail-open) on null.
 *
 * Tool shapes:
 *   - mcp__minsky__session_search_replace, session_edit_file, session_write_file:
 *     `path` field, relative to session workspace (input.cwd)
 *   - Edit, Write (Claude Code): `file_path` field, typically absolute
 */
export function extractTargetPath(
  toolName: string,
  toolInput: Record<string, unknown>,
  cwd: string
): string | null {
  const sessionTools = new Set([
    "mcp__minsky__session_search_replace",
    "mcp__minsky__session_edit_file",
    "mcp__minsky__session_write_file",
  ]);
  const claudeTools = new Set(["Edit", "Write"]);

  if (sessionTools.has(toolName)) {
    const rawPath = toolInput["path"];
    if (typeof rawPath !== "string" || rawPath.trim() === "") return null;
    const trimmed = rawPath.trim();
    // Session tools use paths relative to the session workspace (cwd)
    return isAbsolute(trimmed) ? trimmed : join(cwd, trimmed);
  }

  if (claudeTools.has(toolName)) {
    const rawPath = toolInput["file_path"];
    if (typeof rawPath !== "string" || rawPath.trim() === "") return null;
    const trimmed = rawPath.trim();
    // Claude Code tools generally emit absolute paths, but guard defensively
    return isAbsolute(trimmed) ? trimmed : join(cwd, trimmed);
  }

  return null;
}

// ---------------------------------------------------------------------------
// Banner detection
// ---------------------------------------------------------------------------

/**
 * Result of a banner scan on a file's first N lines.
 */
export interface BannerScanResult {
  /** True iff a generation-banner marker was found. */
  found: boolean;
  /** The name of the matched pattern, if found. */
  patternName?: string;
  /** The line that matched, if found. */
  matchedLine?: string;
  /**
   * 1-indexed line number of the matched line (1–maxLines), if found.
   * Note that markers can appear on any of the first maxLines lines, not
   * just line 1 — this is reported so denial messages show the right line.
   */
  matchedLineNumber?: number;
  /**
   * The reason the scan was inconclusive (file missing, read error, etc.).
   * When set, `found` is always false and the caller should fail-open.
   */
  skipReason?: string;
}

/**
 * Read the first `maxLines` lines of `filePath` and check against
 * GENERATION_BANNER_PATTERNS. Returns a BannerScanResult.
 *
 * Fail-open on any read error or missing file.
 *
 * The `readLines` parameter is injectable for tests.
 */
export async function scanFileForBanner(
  filePath: string,
  maxLines: number = 5,
  readLines?: (path: string, max: number) => Promise<string[]>
): Promise<BannerScanResult> {
  let lines: string[];
  try {
    if (readLines) {
      lines = await readLines(filePath, maxLines);
    } else {
      lines = await readFirstLines(filePath, maxLines);
    }
    // Always enforce the line cap regardless of what the reader returned.
    // This ensures injectable readers in tests don't bypass the 5-line limit.
    lines = lines.slice(0, maxLines);
  } catch (err) {
    return {
      found: false,
      skipReason: `Could not read file: ${err instanceof Error ? err.message : String(err)}`,
    };
  }

  const text = lines.join("\n");

  for (const { re, name } of GENERATION_BANNER_PATTERNS) {
    if (re.test(text)) {
      // Find the specific line that matched for the block message. Markers
      // can appear on any of the first maxLines lines (e.g., a shebang on
      // line 1 with a generation banner on line 2), so we report the
      // 1-indexed line number alongside the line text — PR #1026 R1#2.
      const matchedIdx = lines.findIndex((line) => re.test(line));
      const idx = matchedIdx >= 0 ? matchedIdx : 0;
      const matchedLine = lines[idx] ?? "";
      return {
        found: true,
        patternName: name,
        matchedLine: matchedLine.trim(),
        matchedLineNumber: idx + 1,
      };
    }
  }

  return { found: false };
}

/**
 * Read the first `maxLines` lines of a file using Bun's file API.
 * Returns an empty array if the file doesn't exist.
 */
export async function readFirstLines(filePath: string, maxLines: number): Promise<string[]> {
  const file = Bun.file(filePath);
  const exists = await file.exists();
  if (!exists) {
    return [];
  }

  const text = await file.text();
  return text.split("\n").slice(0, maxLines);
}

// ---------------------------------------------------------------------------
// Denial message formatting
// ---------------------------------------------------------------------------

/**
 * Format a structured denial message for an attempted edit of a generated file.
 */
export function formatDenialReason(
  filePath: string,
  patternName: string,
  matchedLine: string,
  toolName: string,
  matchedLineNumber: number = 1
): string {
  const lines: string[] = [
    `Generated-file edit guard: blocked — the target file appears to be a generated output.`,
    "",
    `  File:    ${filePath}`,
    `  Tool:    ${toolName}`,
    `  Marker:  [${patternName}]`,
    `  Line ${matchedLineNumber}:  ${matchedLine}`,
    "",
    `Generated files must not be edited directly. Find the canonical source and use`,
    `the appropriate authoring API instead. For example:`,
    `  - Rule-pipeline outputs (CLAUDE.md, AGENTS.md, .cursor/rules/*.mdc):`,
    `    Edit the source in .minsky/rules/<name>.mdc, then run:`,
    `      bun run minsky rules compile --target=claude.md`,
    `      bun run minsky rules compile --target=agents.md`,
    `  - Other generated files: consult the generator's documentation.`,
    "",
    `Override (use with caution): set MINSKY_FORCE_EDIT_GENERATED=1 in your`,
    `environment and retry. The override is audit-logged.`,
  ];
  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// Override handling
// ---------------------------------------------------------------------------

/**
 * Returns true if the override env var is set and truthy.
 */
export function isOverrideSet(): boolean {
  const val = process.env["MINSKY_FORCE_EDIT_GENERATED"];
  return val === "1" || val === "true" || val === "yes";
}

/**
 * Emit an audit log line to stdout when the override is active.
 */
export function emitOverrideAuditLog(
  toolName: string,
  filePath: string,
  patternName?: string
): void {
  const ts = new Date().toISOString();
  const markerNote = patternName ? ` matched_marker="${patternName}"` : "";
  process.stdout.write(
    `[check-generated-file-edit] OVERRIDE active (MINSKY_FORCE_EDIT_GENERATED=1) — tool=${toolName} file="${filePath}"${markerNote} ts=${ts}\n`
  );
}

// ---------------------------------------------------------------------------
// Hook entry point
// ---------------------------------------------------------------------------

const GUARDED_TOOLS = new Set([
  "mcp__minsky__session_search_replace",
  "mcp__minsky__session_edit_file",
  "mcp__minsky__session_write_file",
  "Edit",
  "Write",
]);

if (import.meta.main) {
  const input = await readInput<ToolHookInput>();

  // Only act on the guarded tools
  if (!GUARDED_TOOLS.has(input.tool_name)) {
    process.exit(0);
  }

  // Read host cap from settings.json and apply derived budgets. Deferred from
  // module load to entrypoint so importing this module has zero side effects
  // (same pattern as check-branch-fresh.ts — see PR #958 R1 fix).
  const hostCapInfo = readHostCap("check-generated-file-edit.ts", undefined, {
    events: ["PreToolUse"],
  });
  applyHostCap(hostCapInfo.hostCapSec);

  // Extract target file path from tool input
  const targetPath = extractTargetPath(input.tool_name, input.tool_input, input.cwd);
  if (!targetPath) {
    // Can't extract path — fail-open (shape mismatch or unsupported tool variant)
    process.exit(0);
  }

  // Scan the file's first 5 lines for generation-banner markers FIRST so that
  // the override audit log can include the matched marker (PR #1026 R1#3).
  // Trade-off: an override against a not-yet-existing file produces no audit
  // log because nothing was blocked. That's acceptable — the audit only
  // matters when the override actually bypasses a block.
  const scanResult = await scanFileForBanner(targetPath, 5);

  if (scanResult.skipReason) {
    // File missing or unreadable — fail-open
    process.exit(0);
  }

  if (!scanResult.found) {
    // No banner marker — permit
    process.exit(0);
  }

  // Banner found. Check for override; if set, audit-log with the matched
  // marker and permit. Otherwise emit denial.
  if (isOverrideSet()) {
    emitOverrideAuditLog(input.tool_name, targetPath, scanResult.patternName);
    process.exit(0);
  }

  const denialReason = formatDenialReason(
    targetPath,
    scanResult.patternName ?? "unknown",
    scanResult.matchedLine ?? "",
    input.tool_name,
    scanResult.matchedLineNumber ?? 1
  );

  writeOutput({
    hookSpecificOutput: {
      hookEventName: "PreToolUse",
      permissionDecision: "deny",
      permissionDecisionReason: denialReason,
    },
  });
  process.exit(0);
}
